#include <stdio.h>
#include <stdlib.h>
#include <queue>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to get the right side view of the binary tree
void rightSideView(Node* root, int* result, int* index, int level) {
    if (root == NULL) return;
    if (*index == level) {
        result[level] = root->val;
        (*index)++;
    }
    rightSideView(root->right, result, index, level + 1);
    rightSideView(root->left, result, index, level + 1);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* nodes = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &nodes[i]);
        }
        Node* root = NULL;
        // Create the binary tree from the level order traversal
        if (nodes[0] != -1) {
            root = createNode(nodes[0]);
        }
        int queueSize = 1;
        Node** queue = (Node**) malloc(queueSize * sizeof(Node*));
        queue[0] = root;
        int nodeIndex = 1;
        for (int i = 1; i < N; i++) {
            if (nodes[i] != -1) {
                Node* newNode = createNode(nodes[i]);
                if (i % 2 == 1) {
                    queue[(i - 1) / 2]->left = newNode;
                } else {
                    queue[(i - 2) / 2]->right = newNode;
                }
                queue = (Node**) realloc(queue, (queueSize + 1) * sizeof(Node*));
                queue[queueSize] = newNode;
                queueSize++;
            }
        }
        int* result = (int*) malloc(queueSize * sizeof(int));
        int index = 0;
        rightSideView(root, result, &index, 0);
        for (int i = 0; i < index; i++) {
            printf("%d ", result[i]);
        }
        printf("\n");
        free(nodes);
        free(queue);
        free(result);
    }
    return 0;
}

