import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int val;
        Node left;
        Node right;
        Node(int val) {
            this.val = val;
            left = null;
            right = null;
        }
    }

    // Function to get the right side view of the binary tree
    public static void rightSideView(Node root, int[] result, int[] index, int level) {
        if (root == null) return;
        if (index[0] == level) {
            result[level] = root.val;
            index[0]++;
        }
        rightSideView(root.right, result, index, level + 1);
        rightSideView(root.left, result, index, level + 1);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] nodes = new int[N];
            for (int i = 0; i < N; i++) {
                nodes[i] = scanner.nextInt();
            }
            Node root = null;
            // Create the binary tree from the level order traversal
            if (nodes[0] != -1) {
                root = new Node(nodes[0]);
            }
            Queue<Node> queue = new LinkedList<>();
            queue.add(root);
            int nodeIndex = 1;
            while (!queue.isEmpty() && nodeIndex < N) {
                Node node = queue.poll();
                if (nodes[nodeIndex] != -1) {
                    node.left = new Node(nodes[nodeIndex]);
                    queue.add(node.left);
                }
                nodeIndex++;
                if (nodeIndex >= N) break;
                if (nodes[nodeIndex] != -1) {
                    node.right = new Node(nodes[nodeIndex]);
                    queue.add(node.right);
                }
                nodeIndex++;
            }
            int[] result = new int[N];
            int[] index = new int[] {0};
            rightSideView(root, result, index, 0);
            for (int i = 0; i < index[0]; i++) {
                System.out.print(result[i] + " ");
            }
            System.out.println();
        }
    }
}

